// ═══════════════════════════════════════════════════════════════
//  Onne Store RD — Database Engine v65
//  ▸ IndexedDB: storeAdminDB (replaces OnneStoreRD for admin data)
//  ▸ Tables: products, categories, customers, orders, analytics,
//            settings, banners, backups, cache
//  ▸ Full CRUD + indexing + search + pagination
//  ▸ In-memory cache layer (auto-invalidates on writes)
//  ▸ Auto-backup system (periodic + pre-change snapshots)
//  ▸ Prepared for backend migration (API-compatible interface)
// ═══════════════════════════════════════════════════════════════
(function(){ "use strict";

const DB_NAME    = "storeAdminDB";
const DB_VERSION = 3;

// ── Store definitions ──────────────────────────────────────────
const STORES = {
  products:   { keyPath: "id", indexes: [
    { name: "byBrand",    field: "brand",      unique: false },
    { name: "byCategory", field: "categoryId", unique: false },
    { name: "byGender",   field: "gender",     unique: false },
    { name: "byPrice",    field: "price",      unique: false },
    { name: "byName",     field: "nameLower",  unique: false },
    { name: "bySku",      field: "sku",        unique: false },
  ]},
  categories: { keyPath: "id", indexes: [] },
  customers:  { keyPath: "id", indexes: [
    { name: "byEmail", field: "email", unique: false },
    { name: "byName",  field: "nameLower", unique: false },
  ]},
  orders:     { keyPath: "id", indexes: [
    { name: "byCustomer", field: "customerId", unique: false },
    { name: "byDate",     field: "date",       unique: false },
    { name: "byStatus",   field: "status",     unique: false },
  ]},
  analytics:  { keyPath: "id", indexes: [
    { name: "byType", field: "type", unique: false },
    { name: "byDate", field: "date", unique: false },
  ]},
  settings:   { keyPath: "key", indexes: [] },
  banners:    { keyPath: "id", indexes: [] },
  backups:    { keyPath: "id", indexes: [
    { name: "byDate", field: "createdAt", unique: false },
  ]},
  cache:      { keyPath: "key", indexes: [
    { name: "byExpiry", field: "expiry", unique: false },
  ]},
};

// ── In-memory query cache ──────────────────────────────────────
const _memCache = new Map();
const CACHE_TTL = 5 * 60 * 1000; // 5 minutes

let _db = null;

// ── Open DB ────────────────────────────────────────────────────
function openDB(){
  if(_db) return Promise.resolve(_db);
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, DB_VERSION);
    req.onupgradeneeded = e => {
      const db = e.target.result;
      Object.entries(STORES).forEach(([name, cfg]) => {
        let store;
        if(!db.objectStoreNames.contains(name)){
          store = db.createObjectStore(name, { keyPath: cfg.keyPath });
        } else {
          store = e.target.transaction.objectStore(name);
        }
        cfg.indexes.forEach(idx => {
          if(!store.indexNames.contains(idx.name)){
            store.createIndex(idx.name, idx.field, { unique: idx.unique });
          }
        });
      });
    };
    req.onsuccess = e => { _db = e.target.result; resolve(_db); };
    req.onerror   = e => reject(e.target.error);
  });
}

// ── Generic CRUD ───────────────────────────────────────────────
async function _put(storeName, obj){ const db = await openDB(); return new Promise((res,rej)=>{ const tx=db.transaction(storeName,"readwrite"); tx.objectStore(storeName).put(obj).onsuccess=()=>res(obj); tx.onerror=e=>rej(e.target.error); _invalidateCache(storeName); }); }
async function _get(storeName, key){ const db = await openDB(); return new Promise((res,rej)=>{ const tx=db.transaction(storeName,"readonly"); const req=tx.objectStore(storeName).get(key); req.onsuccess=e=>res(e.target.result??null); req.onerror=e=>rej(e.target.error); }); }
async function _del(storeName, key){ const db = await openDB(); return new Promise((res,rej)=>{ const tx=db.transaction(storeName,"readwrite"); tx.objectStore(storeName).delete(key).onsuccess=()=>res(true); tx.onerror=e=>rej(e.target.error); _invalidateCache(storeName); }); }
async function _getAll(storeName){ const db = await openDB(); return new Promise((res,rej)=>{ const tx=db.transaction(storeName,"readonly"); const req=tx.objectStore(storeName).getAll(); req.onsuccess=e=>res(e.target.result||[]); req.onerror=e=>rej(e.target.error); }); }
async function _clear(storeName){ const db = await openDB(); return new Promise((res,rej)=>{ const tx=db.transaction(storeName,"readwrite"); tx.objectStore(storeName).clear().onsuccess=()=>res(true); tx.onerror=e=>rej(e.target.error); _invalidateCache(storeName); }); }
async function _count(storeName){ const db = await openDB(); return new Promise((res,rej)=>{ const tx=db.transaction(storeName,"readonly"); const req=tx.objectStore(storeName).count(); req.onsuccess=e=>res(e.target.result); req.onerror=e=>rej(e.target.error); }); }

// ── Cache helpers ──────────────────────────────────────────────
function _cacheKey(storeName, suffix){ return `${storeName}:${suffix}`; }
function _invalidateCache(storeName){ for(const k of _memCache.keys()){ if(k.startsWith(storeName+":")) _memCache.delete(k); } }
function _fromCache(key){ const e=_memCache.get(key); if(!e) return null; if(Date.now()>e.expiry){ _memCache.delete(key); return null; } return e.value; }
function _toCache(key, value){ _memCache.set(key, { value, expiry: Date.now()+CACHE_TTL }); }

// ══════════════════════════════════════════════════════════════
//  PRODUCTS MODULE
// ══════════════════════════════════════════════════════════════
const Products = {

  // Normalize a product for storage (add searchable fields)
  _norm(p){
    return Object.assign({}, p, {
      nameLower: (p.name||"").toLowerCase(),
      brandLower: (p.brand||"").toLowerCase(),
      sku: p.sku || p.id,
      updatedAt: Date.now(),
    });
  },

  async create(product){
    const obj = this._norm({ id: _uid("p"), createdAt: Date.now(), ...product });
    await _put("products", obj);
    await Analytics.track("product_created", { productId: obj.id });
    return obj;
  },

  async update(product){
    const existing = await _get("products", product.id);
    const merged = this._norm({ ...existing, ...product, updatedAt: Date.now() });
    await _put("products", merged);
    return merged;
  },

  async delete(id){
    await _del("products", id);
    await Analytics.track("product_deleted", { productId: id });
  },

  async get(id){ return _get("products", id); },

  async getAll(){
    const ck = _cacheKey("products","all");
    const cached = _fromCache(ck);
    if(cached) return cached;
    const all = await _getAll("products");
    _toCache(ck, all);
    return all;
  },

  // Paginated list
  async getPage(opts = {}){
    const { page=1, perPage=25, search="", sort="name", dir="asc" } = opts;
    const cacheKey = _cacheKey("products", `page:${page}:${perPage}:${search}:${sort}:${dir}`);
    const cached = _fromCache(cacheKey);
    if(cached) return cached;

    let items = await this.getAll();

    // Filter
    if(search){
      const q = search.toLowerCase();
      items = items.filter(p =>
        (p.name||"").toLowerCase().includes(q) ||
        (p.brand||"").toLowerCase().includes(q) ||
        (p.sku||"").toLowerCase().includes(q) ||
        String(p.price||"").includes(q)
      );
    }

    // Sort
    items = items.slice().sort((a,b)=>{
      let va = a[sort]??"", vb = b[sort]??"";
      if(typeof va === "number") return dir==="asc" ? va-vb : vb-va;
      va = String(va).toLowerCase(); vb = String(vb).toLowerCase();
      return dir==="asc" ? va.localeCompare(vb) : vb.localeCompare(va);
    });

    const total = items.length;
    const totalPages = Math.max(1, Math.ceil(total / perPage));
    const start = (page-1) * perPage;
    const result = {
      items: items.slice(start, start+perPage),
      total, totalPages, page, perPage,
      hasNext: page < totalPages,
      hasPrev: page > 1,
    };
    _toCache(cacheKey, result);
    return result;
  },

  // Search with indexing
  async search(query, opts = {}){
    const { limit=20, categoryId, gender, onSale, featured, newFlag } = opts;
    const q = (query||"").toLowerCase().trim();
    const cacheKey = _cacheKey("products", `search:${q}:${categoryId}:${gender}:${onSale}:${featured}`);
    const cached = _fromCache(cacheKey);
    if(cached) return cached;

    let items = await this.getAll();
    if(q) items = items.filter(p =>
      (p.nameLower||"").includes(q) ||
      (p.brandLower||"").includes(q) ||
      (p.description||"").toLowerCase().includes(q) ||
      (p.sku||"").toLowerCase().includes(q)
    );
    if(categoryId) items = items.filter(p => p.categoryId === categoryId);
    if(gender)     items = items.filter(p => p.gender === gender);
    if(onSale)     items = items.filter(p => p.onSale);
    if(featured)   items = items.filter(p => p.featured);
    if(newFlag)    items = items.filter(p => p.new);

    // Score by relevance
    if(q){
      items = items.map(p => {
        const hay = `${p.nameLower} ${p.brandLower} ${p.description||""}`;
        let score = 0;
        if((p.nameLower||"").startsWith(q)) score += 10;
        if((p.nameLower||"").includes(q))   score += 5;
        if((p.brandLower||"").includes(q))  score += 3;
        if(hay.includes(q))                  score += 1;
        return { ...p, _score: score };
      }).sort((a,b) => b._score - a._score);
    }

    const result = items.slice(0, limit);
    _toCache(cacheKey, result);
    return result;
  },

  async count(){ return _count("products"); },

  // Bulk import from JSON (migration helper)
  async bulkImport(products){
    const db = await openDB();
    return new Promise((res,rej) => {
      const tx = db.transaction("products", "readwrite");
      const st = tx.objectStore("products");
      let count = 0;
      products.forEach(p => { st.put(this._norm(p)); count++; });
      tx.oncomplete = () => { _invalidateCache("products"); res(count); };
      tx.onerror = e => rej(e.target.error);
    });
  },
};

// ══════════════════════════════════════════════════════════════
//  CUSTOMERS MODULE
// ══════════════════════════════════════════════════════════════
const Customers = {
  async create(customer){
    const obj = { id: _uid("cust"), createdAt: Date.now(), totalSpent: 0, orders: [], ...customer, nameLower: (customer.name||"").toLowerCase() };
    await _put("customers", obj); return obj;
  },
  async update(customer){ const ex = await _get("customers", customer.id); return _put("customers", { ...ex, ...customer, nameLower: (customer.name||ex?.name||"").toLowerCase(), updatedAt: Date.now() }); },
  async delete(id){ return _del("customers", id); },
  async get(id){ return _get("customers", id); },
  async getAll(){ return _getAll("customers"); },
  async getPage(opts = {}){
    const { page=1, perPage=20, search="" } = opts;
    let items = await this.getAll();
    if(search){ const q=search.toLowerCase(); items=items.filter(c=>(c.name||"").toLowerCase().includes(q)||(c.email||"").toLowerCase().includes(q)||(c.phone||"").includes(q)); }
    items.sort((a,b)=>(b.createdAt||0)-(a.createdAt||0));
    const total=items.length, totalPages=Math.max(1,Math.ceil(total/perPage)), start=(page-1)*perPage;
    return { items: items.slice(start,start+perPage), total, totalPages, page, perPage };
  },
  // Record a purchase for a customer
  async recordPurchase(customerId, orderId, amount){
    const c = await this.get(customerId);
    if(!c) return;
    c.totalSpent = (c.totalSpent||0) + amount;
    c.orders = [...(c.orders||[]), orderId];
    c.lastPurchase = Date.now();
    await _put("customers", c);
  },
  async count(){ return _count("customers"); },
};

// ══════════════════════════════════════════════════════════════
//  ANALYTICS MODULE
// ══════════════════════════════════════════════════════════════
const Analytics = {

  async track(type, data = {}){
    try {
      await _put("analytics", {
        id: _uid("ev"),
        type,
        date: _dateStr(),
        ts: Date.now(),
        ...data
      });
    } catch(e) { /* non-critical */ }
  },

  async getByType(type){
    const all = await _getAll("analytics");
    return all.filter(e => e.type === type);
  },

  async getSalesByDay(days = 30){
    const cutoff = Date.now() - days * 86400000;
    const all = await _getAll("analytics");
    const sales = all.filter(e => e.type === "order_completed" && e.ts > cutoff);
    const map = {};
    sales.forEach(e => {
      const d = e.date || _dateStr(e.ts);
      map[d] = (map[d]||0) + (e.total||0);
    });
    return Object.entries(map).sort((a,b) => a[0].localeCompare(b[0])).map(([date, total]) => ({ date, total }));
  },

  async getTopProducts(limit = 10){
    const all = await _getAll("analytics");
    const views = all.filter(e => e.type === "product_view");
    const map = {};
    views.forEach(e => {
      if(e.productId) map[e.productId] = (map[e.productId]||0)+1;
    });
    return Object.entries(map).sort((a,b) => b[1]-a[1]).slice(0,limit).map(([id,count])=>({id,count}));
  },

  async getSummary(){
    const all = await _getAll("analytics");
    const orders     = all.filter(e=>e.type==="order_completed");
    const views      = all.filter(e=>e.type==="product_view");
    const cartAdds   = all.filter(e=>e.type==="cart_add");
    const totalRevenue = orders.reduce((s,e)=>s+(e.total||0),0);
    const today = _dateStr();
    const todayOrders  = orders.filter(e=>e.date===today);
    const todayRevenue = todayOrders.reduce((s,e)=>s+(e.total||0),0);
    return {
      totalOrders: orders.length,
      totalRevenue,
      totalViews: views.length,
      totalCartAdds: cartAdds.length,
      todayOrders: todayOrders.length,
      todayRevenue,
      conversionRate: views.length > 0 ? ((orders.length/views.length)*100).toFixed(1) : "0.0",
    };
  },

  async clear(){ return _clear("analytics"); },
};

// ══════════════════════════════════════════════════════════════
//  BACKUP MODULE
// ══════════════════════════════════════════════════════════════
const Backup = {

  MAX_BACKUPS: 10,

  async create(label = "auto"){
    // Get current state from localStorage
    const configStr = localStorage.getItem("siteConfig") || "{}";
    let config;
    try { config = JSON.parse(configStr); } catch(e) { config = {}; }

    const id = _uid("bak");
    const backup = {
      id,
      label,
      createdAt: Date.now(),
      createdAtStr: new Date().toLocaleString("es-DO"),
      size: configStr.length,
      data: configStr,
    };
    await _put("backups", backup);

    // Prune old backups
    await this._prune();
    return backup;
  },

  async restore(id){
    const b = await _get("backups", id);
    if(!b) return false;
    try {
      JSON.parse(b.data); // validate
      localStorage.setItem("siteConfig", b.data);
      return true;
    } catch(e) { return false; }
  },

  async list(){
    const all = await _getAll("backups");
    return all.sort((a,b) => b.createdAt - a.createdAt);
  },

  async delete(id){ return _del("backups", id); },

  async _prune(){
    const all = await this.list();
    const auto = all.filter(b=>b.label==="auto");
    if(auto.length > this.MAX_BACKUPS){
      const toDelete = auto.slice(this.MAX_BACKUPS);
      for(const b of toDelete) await _del("backups", b.id);
    }
  },

  // Auto-backup every 30 minutes
  startAutoBackup(intervalMs = 30 * 60 * 1000){
    if(this._timer) clearInterval(this._timer);
    this._timer = setInterval(()=>{
      this.create("auto").catch(()=>{});
    }, intervalMs);
    // Also do one immediately
    setTimeout(()=>this.create("auto").catch(()=>{}), 5000);
  },

  // Export as downloadable JSON
  exportJSON(){
    const configStr = localStorage.getItem("siteConfig") || "{}";
    let cfg;
    try { cfg = JSON.parse(configStr); } catch(e) { cfg = {}; }
    const exportObj = {
      version: "65",
      exportedAt: new Date().toISOString(),
      source: "OnneStoreRD",
      config: cfg,
    };
    const blob = new Blob([JSON.stringify(exportObj, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `onne-store-backup-${_dateStr()}.json`;
    a.click();
    URL.revokeObjectURL(url);
  },

  // Import from JSON file
  async importJSON(jsonStr){
    let obj;
    try { obj = JSON.parse(jsonStr); } catch(e) { throw new Error("JSON inválido"); }
    const cfg = obj.config || obj;
    if(!cfg) throw new Error("Archivo inválido — no se encontró configuración");
    // Backup current state before importing
    await this.create("pre-import");
    localStorage.setItem("siteConfig", JSON.stringify(cfg));
    return cfg;
  },
};

// ══════════════════════════════════════════════════════════════
//  SETTINGS MODULE
// ══════════════════════════════════════════════════════════════
const Settings = {
  async get(key, fallback = null){ const r = await _get("settings", key); return r?.value ?? fallback; },
  async set(key, value){ await _put("settings", { key, value, updatedAt: Date.now() }); },
  async getAll(){ const all = await _getAll("settings"); return Object.fromEntries(all.map(e=>[e.key, e.value])); },
};

// ══════════════════════════════════════════════════════════════
//  RECOMMENDATIONS ENGINE
// ══════════════════════════════════════════════════════════════
const Recommendations = {

  // Get product recommendations based on current product
  async forProduct(productId, allProducts, limit = 4){
    const target = allProducts.find(p=>p.id===productId);
    if(!target) return allProducts.slice(0,limit);

    const top = await Analytics.getTopProducts(20);
    const topIds = new Set(top.map(t=>t.id));

    return allProducts
      .filter(p => p.id !== productId)
      .map(p => {
        let score = 0;
        if(p.categoryId === target.categoryId) score += 10;
        if(p.gender === target.gender) score += 5;
        if(p.brand === target.brand) score += 8;
        if(topIds.has(p.id)) score += 3;
        if(p.featured) score += 2;
        if(p.new) score += 1;
        // Price similarity
        const priceDiff = Math.abs((p.price||0) - (target.price||0));
        if(priceDiff < 500) score += 4;
        else if(priceDiff < 1500) score += 2;
        return { ...p, _recScore: score };
      })
      .sort((a,b) => b._recScore - a._recScore)
      .slice(0, limit);
  },

  // Get trending products
  async getTrending(allProducts, limit = 8){
    const top = await Analytics.getTopProducts(limit * 2);
    const topMap = new Map(top.map(t=>[t.id, t.count]));
    return allProducts
      .map(p => ({ ...p, _views: topMap.get(p.id)||0 }))
      .sort((a,b) => (b._views - a._views) || (b.featured?1:0) - (a.featured?1:0))
      .slice(0, limit);
  },
};

// ── Utility helpers ───────────────────────────────────────────
function _uid(prefix="id"){ return prefix+"_"+Date.now().toString(36)+Math.random().toString(36).slice(2,6); }
function _dateStr(ts){ const d=ts?new Date(ts):new Date(); return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`; }

// ── Storage usage ─────────────────────────────────────────────
async function getStorageUsage(){
  if(!navigator.storage?.estimate) return { usageMB:"?", quotaMB:"?", percent:0 };
  const { usage, quota } = await navigator.storage.estimate();
  return {
    usage, quota,
    percent: Math.round((usage/quota)*100),
    usageMB: (usage/1024/1024).toFixed(1),
    quotaMB: (quota/1024/1024).toFixed(0),
  };
}

// ── Initialize DB on load ─────────────────────────────────────
openDB().then(()=>{
  Backup.startAutoBackup();
}).catch(e => console.warn("[StoreDB] Init failed:", e));

// ── Expose global API ─────────────────────────────────────────
window.StoreDB = {
  Products,
  Customers,
  Analytics,
  Backup,
  Settings,
  Recommendations,
  getStorageUsage,
  openDB,

  // Migration helper: sync localStorage products → IndexedDB
  async syncFromLocalStorage(cfg){
    if(!cfg?.products?.length) return 0;
    const count = await Products.bulkImport(cfg.products);
    console.log(`[StoreDB] Synced ${count} products from localStorage`);
    return count;
  },
};

})();

/* ╔══════════════════════════════════════════════════════════
 * ║  migrate.js
 * ╚══════════════════════════════════════════════════════════ */

/* ═══════════════════════════════════════════════════════════════════
   OnneStoreRD — Migration System v1.0
   Migrates all data from IndexedDB / localStorage → Backend REST API
   
   Usage:
     const migrator = new OnneMigrator({ apiUrl: 'https://api.onnestore.rd', token: 'xxx' });
     const result = await migrator.migrateAll();
     console.log(result.summary);
   
   Or use the UI: call migrator.openPanel() to show the migration dialog
═══════════════════════════════════════════════════════════════════ */

(function(root) {
  'use strict';

  // ── Constants ──────────────────────────────────────────────────
  const MIGRATION_VERSION = '1.0.0';
  const LS_KEY            = 'onne_cfg';
  const IDB_NAME          = 'OnneStore';
  const IDB_VERSION       = 3;

  // ── Utility ────────────────────────────────────────────────────
  function log(level, msg, data) {
    const ts = new Date().toISOString();
    const entry = { ts, level, msg, data: data || null };
    console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](`[Migrator ${ts}] ${msg}`, data || '');
    return entry;
  }

  function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

  function esc(s) {
    if (!s) return '';
    return String(s).replace(/[<>"']/g, c => ({'<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }

  // ── IDB Helper ─────────────────────────────────────────────────
  class IDBHelper {
    constructor() { this.db = null; }

    async open() {
      return new Promise((resolve, reject) => {
        const req = indexedDB.open(IDB_NAME, IDB_VERSION);
        req.onsuccess  = e => { this.db = e.target.result; resolve(this.db); };
        req.onerror    = e => reject(e.target.error);
        req.onupgradeneeded = e => {
          // Don't create new stores — we're reading existing ones
          this.db = e.target.result;
        };
      });
    }

    async getAll(storeName) {
      if (!this.db) await this.open();
      const stores = Array.from(this.db.objectStoreNames);
      if (!stores.includes(storeName)) return [];
      return new Promise((resolve, reject) => {
        const tx   = this.db.transaction(storeName, 'readonly');
        const req  = tx.objectStore(storeName).getAll();
        req.onsuccess = e => resolve(e.target.result || []);
        req.onerror   = e => reject(e.target.error);
      });
    }

    listStores() {
      return this.db ? Array.from(this.db.objectStoreNames) : [];
    }

    close() { if (this.db) this.db.close(); }
  }

  // ── API Client ──────────────────────────────────────────────────
  class ApiClient {
    constructor(baseUrl, token) {
      this.baseUrl = baseUrl.replace(/\/$/, '');
      this.token   = token;
    }

    async request(method, path, body) {
      const url = `${this.baseUrl}${path}`;
      const opts = {
        method,
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${this.token}`,
          'X-Migration-Version': MIGRATION_VERSION,
        },
      };
      if (body) opts.body = JSON.stringify(body);
      
      const res = await fetch(url, opts);
      const data = await res.json().catch(() => ({}));
      
      if (!res.ok) {
        throw new Error(`API ${method} ${path} → ${res.status}: ${data.message || res.statusText}`);
      }
      return data;
    }

    get  (path)       { return this.request('GET',    path); }
    post (path, body) { return this.request('POST',   path, body); }
    put  (path, body) { return this.request('PUT',    path, body); }
    patch(path, body) { return this.request('PATCH',  path, body); }
  }

  // ══════════════════════════════════════════════════════════════
  //  MAIN MIGRATOR CLASS
  // ══════════════════════════════════════════════════════════════
  class OnneMigrator {
    constructor(options = {}) {
      this.apiUrl    = options.apiUrl || '';
      this.token     = options.token  || '';
      this.batchSize = options.batchSize || 20;
      this.dryRun    = options.dryRun || false;
      this.onProgress= options.onProgress || null;

      this.idb    = new IDBHelper();
      this.api    = this.apiUrl ? new ApiClient(this.apiUrl, this.token) : null;
      this.logs   = [];
      this.errors = [];

      this._report = {
        config:     { total: 0, done: 0, failed: 0 },
        products:   { total: 0, done: 0, failed: 0 },
        customers:  { total: 0, done: 0, failed: 0 },
        spaces:     { total: 0, done: 0, failed: 0 },
        botReplies: { total: 0, done: 0, failed: 0 },
        analytics:  { total: 0, done: 0, failed: 0 },
        backups:    { total: 0, done: 0, failed: 0 },
      };
    }

    _log(level, msg, data) {
      const entry = log(level, msg, data);
      this.logs.push(entry);
      return entry;
    }

    _progress(step, current, total, msg) {
      const pct = total > 0 ? Math.round((current / total) * 100) : 0;
      if (this.onProgress) {
        this.onProgress({ step, current, total, pct, msg });
      }
    }

    // ── STEP 1: Read localStorage config ───────────────────────
    readLocalStorageConfig() {
      this._log('info', 'Reading localStorage config...');
      try {
        const raw = localStorage.getItem(LS_KEY);
        if (!raw) { this._log('warn', 'No localStorage config found'); return null; }
        const cfg = JSON.parse(raw);
        this._log('info', `Config loaded: ${Object.keys(cfg).length} top-level keys`);
        return cfg;
      } catch(e) {
        this._log('error', 'Failed to read localStorage', e.message);
        return null;
      }
    }

    // ── STEP 2: Migrate site configuration ─────────────────────
    async migrateConfig(cfg) {
      if (!cfg) return;
      this._log('info', 'Migrating site configuration...');
      this._report.config.total = 1;
      this._progress('config', 0, 1, 'Sending site config...');

      const payload = {
        basic: {
          storeName:   cfg.storeName     || 'ONNE STORE',
          storeEmail:  cfg.storeEmail    || '',
          storePhone:  cfg.storePhone    || '',
          storeSlug:   cfg.storeSlug     || 'onne-store',
          logoUrl:     cfg.logoUrl       || '',
          faviconUrl:  cfg.faviconUrl    || '',
          currency:    cfg.currency      || 'RD$',
          country:     cfg.country       || 'DO',
        },
        theme: {
          colors: {
            gold:      cfg.colorGold     || '#C9A96E',
            charcoal:  cfg.colorCharcoal || '#1C1C1E',
            white:     cfg.colorWhite    || '#FFFFFF',
            offWhite:  cfg.colorOff      || '#F5F0E8',
          },
          fonts: cfg.fonts || {},
        },
        banner: cfg.banner || {},
        navigation: cfg.navigation || cfg.navLinks || [],
        whatsapp: cfg.whatsapp || {},
        footer: cfg.footer || {},
        shipping: {
          zones: cfg.shippingZones || cfg.deliveryZones || [],
          defaultCost: cfg.defaultShipping || 0,
        },
        shopTabs: cfg.shopTabs || {},
        announce: cfg.announce || {},
        features: cfg.features || [],
        testimonials: cfg.testimonials || [],
        about: cfg.about || {},
      };

      if (!this.dryRun && this.api) {
        try {
          await this.api.put('/api/config', payload);
          this._report.config.done = 1;
          this._log('info', 'Config migrated ✓');
        } catch(e) {
          this._report.config.failed = 1;
          this._log('error', 'Config migration failed', e.message);
          this.errors.push({ type: 'config', error: e.message });
        }
      } else {
        this._report.config.done = 1;
        this._log('info', '[DRY RUN] Config would be migrated');
      }

      this._progress('config', 1, 1, 'Config done');
    }

    // ── STEP 3: Migrate products from IDB ──────────────────────
    async migrateProducts(cfg) {
      this._log('info', 'Migrating products...');
      
      // Try IDB first, fallback to config.products
      let products = [];
      try {
        await this.idb.open();
        const idbProds = await this.idb.getAll('products');
        if (idbProds.length) {
          products = idbProds;
          this._log('info', `Found ${products.length} products in IndexedDB`);
        }
      } catch(e) {
        this._log('warn', 'IDB products unavailable, trying localStorage', e.message);
      }

      if (!products.length && cfg?.products?.length) {
        products = cfg.products;
        this._log('info', `Found ${products.length} products in localStorage config`);
      }

      if (!products.length) {
        this._log('warn', 'No products found');
        return;
      }

      this._report.products.total = products.length;
      
      // Process in batches
      for (let i = 0; i < products.length; i += this.batchSize) {
        const batch = products.slice(i, i + this.batchSize);
        this._progress('products', i, products.length, `Migrating products ${i+1}–${Math.min(i+this.batchSize, products.length)} of ${products.length}`);
        
        for (const p of batch) {
          const payload = this._normalizeProduct(p);
          if (!this.dryRun && this.api) {
            try {
              await this.api.post('/api/products', payload);
              this._report.products.done++;
            } catch(e) {
              this._report.products.failed++;
              this._log('error', `Product failed: ${p.name}`, e.message);
              this.errors.push({ type: 'product', id: p.id, name: p.name, error: e.message });
            }
          } else {
            this._report.products.done++;
          }
          await sleep(30); // throttle
        }
      }

      this._log('info', `Products: ${this._report.products.done} done, ${this._report.products.failed} failed`);
    }

    _normalizeProduct(p) {
      return {
        id:          p.id || null,
        name:        p.name || 'Sin nombre',
        brand:       p.brand || '',
        description: p.description || p.desc || '',
        gender:      ['Mujer','Hombre','Unisex'].includes(p.gender) ? p.gender : 'Unisex',
        volumeMl:    parseInt(p.ml || p.volumeMl || 0) || null,
        price:       parseFloat(p.price || 0),
        salePrice:   p.salePrice ? parseFloat(p.salePrice) : null,
        stock:       parseInt(p.stock || 0),
        categoryId:  p.categoryId || p.tabId || null,
        subcategory: p.subcategory || '',
        imageUrl:    p.imageUrl || p.image || '',
        images:      Array.isArray(p.images) ? p.images : [],
        tags:        Array.isArray(p.tags) ? p.tags : [],
        isActive:    p.active !== false && p.isActive !== false,
        isFeatured:  !!(p.featured || p.isFeatured),
        isNew:       !!(p.new || p.isNew),
        sortOrder:   parseInt(p.sortOrder || p.order || 0),
      };
    }

    // ── STEP 4: Migrate customers ───────────────────────────────
    async migrateCustomers(cfg) {
      this._log('info', 'Migrating customers...');
      
      let customers = [];
      try {
        const idbCusts = await this.idb.getAll('customers');
        if (idbCusts.length) { customers = idbCusts; }
      } catch(e) {}

      if (!customers.length && cfg?.customers?.length) {
        customers = cfg.customers;
      }

      if (!customers.length) {
        this._log('warn', 'No customers found');
        return;
      }

      this._report.customers.total = customers.length;
      this._progress('customers', 0, customers.length, 'Starting customer migration...');

      for (let i = 0; i < customers.length; i++) {
        const c = customers[i];
        this._progress('customers', i, customers.length, `Customer: ${c.name || c.email}`);
        
        const payload = {
          id:         c.id || null,
          name:       c.name || 'Sin nombre',
          email:      c.email || '',
          phone:      c.phone || c.whatsapp || '',
          city:       c.city || '',
          address:    c.address || '',
          notes:      c.notes || '',
          totalSpent: parseFloat(c.totalSpent || 0),
          orderCount: parseInt(c.orderCount || c.orders?.length || 0),
          createdAt:  c.createdAt || new Date().toISOString(),
        };

        if (!this.dryRun && this.api) {
          try {
            await this.api.post('/api/customers', payload);
            this._report.customers.done++;
          } catch(e) {
            this._report.customers.failed++;
            this.errors.push({ type: 'customer', id: c.id, name: c.name, error: e.message });
          }
        } else {
          this._report.customers.done++;
        }
        await sleep(20);
      }

      this._log('info', `Customers: ${this._report.customers.done} done, ${this._report.customers.failed} failed`);
    }

    // ── STEP 5: Migrate spaces ──────────────────────────────────
    async migrateSpaces(cfg) {
      this._log('info', 'Migrating spaces...');
      
      let spaces = [];
      try {
        const idbSpaces = await this.idb.getAll('spaces');
        if (idbSpaces.length) { spaces = idbSpaces; }
      } catch(e) {}

      if (!spaces.length && cfg?.spaces?.length) {
        spaces = cfg.spaces;
      }

      if (!spaces.length) {
        this._log('info', 'No spaces to migrate');
        return;
      }

      this._report.spaces.total = spaces.length;

      for (let i = 0; i < spaces.length; i++) {
        const s = spaces[i];
        this._progress('spaces', i, spaces.length, `Space: ${s.title || s.slug}`);
        
        const payload = {
          id:          s.id || null,
          slug:        s.slug || s.id || `space-${i}`,
          title:       s.title || 'Sin título',
          description: s.description || '',
          blocks:      Array.isArray(s.blocks) ? s.blocks : [],
          seoTitle:    s.seoTitle || s.metaTitle || '',
          seoDesc:     s.seoDesc  || s.metaDesc  || '',
          isActive:    s.active !== false && s.isActive !== false,
          sortOrder:   parseInt(s.sortOrder || i),
        };

        if (!this.dryRun && this.api) {
          try {
            await this.api.post('/api/spaces', payload);
            this._report.spaces.done++;
          } catch(e) {
            this._report.spaces.failed++;
            this.errors.push({ type: 'space', id: s.id, slug: s.slug, error: e.message });
          }
        } else {
          this._report.spaces.done++;
        }
        await sleep(20);
      }

      this._log('info', `Spaces: ${this._report.spaces.done} done`);
    }

    // ── STEP 6: Migrate bot replies ─────────────────────────────
    async migrateBotReplies(cfg) {
      const replies = cfg?.whatsapp?.chatbot?.botReplies || [];
      if (!replies.length) { this._log('info', 'No bot replies to migrate'); return; }
      
      this._report.botReplies.total = replies.length;
      this._log('info', `Migrating ${replies.length} bot replies...`);

      const payload = replies.map((r, i) => ({
        keyword:   r.keyword || '',
        reply:     r.reply || '',
        isExact:   !!(r.exact || r.isExact),
        isActive:  r.active !== false,
        sortOrder: i,
      })).filter(r => r.keyword && r.reply);

      if (!this.dryRun && this.api) {
        try {
          await this.api.post('/api/bot/replies/bulk', { replies: payload });
          this._report.botReplies.done = payload.length;
        } catch(e) {
          this._report.botReplies.failed = payload.length;
          this.errors.push({ type: 'botReplies', error: e.message });
        }
      } else {
        this._report.botReplies.done = payload.length;
      }
    }

    // ── STEP 7: Migrate analytics events from IDB ───────────────
    async migrateAnalytics() {
      this._log('info', 'Migrating analytics events...');
      let events = [];
      
      try {
        events = await this.idb.getAll('analytics');
      } catch(e) {
        this._log('warn', 'No analytics store found in IDB');
        return;
      }

      if (!events.length) { this._log('info', 'No analytics events to migrate'); return; }

      this._report.analytics.total = events.length;
      this._log('info', `Found ${events.length} analytics events`);

      // Send in larger batches (100 at a time)
      const BATCH = 100;
      for (let i = 0; i < events.length; i += BATCH) {
        const batch = events.slice(i, i + BATCH).map(e => ({
          eventType:  e.type || e.eventType || 'view',
          productId:  e.productId || e.id || null,
          sessionId:  e.sessionId || null,
          meta:       e.meta || {},
          createdAt:  e.timestamp || e.createdAt || new Date().toISOString(),
        }));

        this._progress('analytics', i, events.length, `Analytics ${i}–${i+BATCH}...`);

        if (!this.dryRun && this.api) {
          try {
            await this.api.post('/api/analytics/bulk', { events: batch });
            this._report.analytics.done += batch.length;
          } catch(e) {
            this._report.analytics.failed += batch.length;
            this._log('warn', `Analytics batch failed`, e.message);
          }
        } else {
          this._report.analytics.done += batch.length;
        }
        await sleep(50);
      }

      this._log('info', `Analytics: ${this._report.analytics.done} migrated`);
    }

    // ── STEP 8: Create initial backup ───────────────────────────
    async createBackup(cfg) {
      if (!this.api || this.dryRun) return;
      this._log('info', 'Creating pre-migration backup...');
      try {
        const backupData = {
          source:    'migration-v1',
          timestamp: new Date().toISOString(),
          data:      cfg,
          idbStores: this.idb.listStores(),
        };
        await this.api.post('/api/backups', {
          label: 'pre-migration',
          notes: 'Auto-backup before IndexedDB migration',
          data:  backupData,
        });
        this._report.backups.done = 1;
        this._log('info', 'Pre-migration backup created ✓');
      } catch(e) {
        this._log('warn', 'Backup failed (non-critical)', e.message);
      }
    }

    // ── MAIN MIGRATION ORCHESTRATOR ─────────────────────────────
    async migrateAll() {
      const startTime = Date.now();
      this._log('info', `=== OnneStoreRD Migration v${MIGRATION_VERSION} START ===`);
      this._log('info', `Mode: ${this.dryRun ? 'DRY RUN (no API calls)' : 'LIVE'}`);
      this._log('info', `API: ${this.apiUrl || '(not configured)'}`);

      try {
        // 1. Read source data
        this._progress('init', 0, 8, 'Reading local storage...');
        const cfg = this.readLocalStorageConfig();

        // 2. Open IDB
        this._progress('init', 1, 8, 'Opening IndexedDB...');
        try { await this.idb.open(); } catch(e) {
          this._log('warn', 'IDB unavailable', e.message);
        }

        // 3. Create backup first
        this._progress('backup', 0, 1, 'Creating backup...');
        await this.createBackup(cfg);

        // 4. Run all migrations
        this._progress('config', 0, 1, 'Migrating config...');
        await this.migrateConfig(cfg);

        this._progress('products', 0, 100, 'Migrating products...');
        await this.migrateProducts(cfg);

        this._progress('customers', 0, 100, 'Migrating customers...');
        await this.migrateCustomers(cfg);

        this._progress('spaces', 0, 100, 'Migrating spaces...');
        await this.migrateSpaces(cfg);

        this._progress('botReplies', 0, 1, 'Migrating bot replies...');
        await this.migrateBotReplies(cfg);

        this._progress('analytics', 0, 100, 'Migrating analytics...');
        await this.migrateAnalytics();

      } catch(e) {
        this._log('error', 'Migration failed with exception', e.message);
        this.errors.push({ type: 'fatal', error: e.message, stack: e.stack });
      } finally {
        this.idb.close();
      }

      const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
      this._log('info', `=== Migration COMPLETE in ${elapsed}s ===`);

      const summary = this._buildSummary(elapsed);
      this._log('info', 'Summary:', summary);
      
      return { summary, logs: this.logs, errors: this.errors };
    }

    _buildSummary(elapsed) {
      const r = this._report;
      const totalItems = Object.values(r).reduce((s, v) => s + v.total, 0);
      const totalDone  = Object.values(r).reduce((s, v) => s + v.done, 0);
      const totalFailed= Object.values(r).reduce((s, v) => s + v.failed, 0);
      return {
        version:     MIGRATION_VERSION,
        dryRun:      this.dryRun,
        elapsed:     elapsed + 's',
        totals:      { items: totalItems, done: totalDone, failed: totalFailed },
        bySection:   r,
        errors:      this.errors.length,
        success:     totalFailed === 0,
      };
    }

    // ── UI PANEL ────────────────────────────────────────────────
    openPanel() {
      // Remove existing panel
      const old = document.getElementById('onne-migrator-panel');
      if (old) old.remove();

      const panel = document.createElement('div');
      panel.id = 'onne-migrator-panel';
      panel.innerHTML = `
      <style>
        #onne-migrator-panel {
          position:fixed; inset:0; background:rgba(0,0,0,.7); z-index:99999;
          display:flex; align-items:center; justify-content:center; padding:20px;
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
        }
        #omp-box {
          background:#fff; border-radius:20px; width:100%; max-width:620px;
          max-height:90vh; overflow-y:auto; box-shadow:0 24px 60px rgba(0,0,0,.3);
        }
        #omp-header { padding:24px 28px 0; border-bottom:1px solid #eee; padding-bottom:18px; margin-bottom:0; }
        #omp-header h2 { font-size:1.1rem; font-weight:700; color:#1e1e1e; margin:0; }
        #omp-header p  { font-size:.8rem; color:#888; margin:4px 0 0; }
        #omp-body { padding:20px 28px; }
        #omp-form .row { margin-bottom:14px; }
        #omp-form label { display:block; font-size:.78rem; font-weight:600; color:#555; margin-bottom:5px; }
        #omp-form input { width:100%; padding:9px 12px; border:1.5px solid #ddd; border-radius:10px;
          font-size:.84rem; outline:none; box-sizing:border-box; }
        #omp-form input:focus { border-color:#C9A96E; box-shadow:0 0 0 3px rgba(201,169,110,.12); }
        .omp-check-row { display:flex; align-items:center; gap:8px; font-size:.82rem; color:#555; margin-bottom:14px; cursor:pointer; }
        .omp-check-row input[type=checkbox] { width:18px; height:18px; accent-color:#C9A96E; cursor:pointer; }
        #omp-progress { display:none; margin:16px 0; }
        #omp-progress-bar { height:8px; background:#eee; border-radius:4px; overflow:hidden; margin-bottom:8px; }
        #omp-progress-fill { height:100%; background:linear-gradient(90deg,#C9A96E,#d4b07a); border-radius:4px;
          transition:width .3s ease; width:0; }
        #omp-progress-msg  { font-size:.78rem; color:#888; }
        #omp-result { display:none; margin-top:16px; }
        .omp-stat-grid { display:grid; grid-template-columns:repeat(auto-fill,minmax(130px,1fr)); gap:10px; margin:14px 0; }
        .omp-stat { background:#fafafa; border:1px solid #eee; border-radius:12px; padding:12px; text-align:center; }
        .omp-stat-val { font-size:1.6rem; font-weight:700; color:#1e1e1e; }
        .omp-stat-lbl { font-size:.7rem; color:#888; text-transform:uppercase; letter-spacing:.06em; margin-top:2px; }
        .omp-stat.ok   .omp-stat-val { color:#16a34a; }
        .omp-stat.err  .omp-stat-val { color:#dc2626; }
        #omp-log { font-family:monospace; font-size:.72rem; background:#1e1e1e; color:#c8ffa0;
          border-radius:10px; padding:14px; max-height:180px; overflow-y:auto; white-space:pre-wrap; margin-top:14px; }
        #omp-actions { display:flex; gap:10px; flex-wrap:wrap; margin-top:18px; }
        .omp-btn { padding:10px 20px; border-radius:20px; font-size:.82rem; font-weight:700;
          border:none; cursor:pointer; transition:all .15s; display:inline-flex; align-items:center; gap:6px; }
        .omp-btn-primary { background:#C9A96E; color:#fff; }
        .omp-btn-primary:hover { background:#b8944e; transform:translateY(-1px); }
        .omp-btn-secondary { background:transparent; border:1.5px solid rgba(0,0,0,.15); color:#555; }
        .omp-btn-secondary:hover { background:rgba(0,0,0,.04); }
        .omp-btn-danger { background:#E07068; color:#fff; }
        .omp-btn:disabled { opacity:.4; pointer-events:none; }
        #omp-close { position:absolute; top:16px; right:16px; width:32px; height:32px; border-radius:50%;
          background:rgba(0,0,0,.07); border:none; font-size:1rem; cursor:pointer; color:#555; }
      </style>
      <div id="omp-box" style="position:relative">
        <button id="omp-close">✕</button>
        <div id="omp-header">
          <h2>🚀 Migración de Datos → Backend</h2>
          <p>Transfiere toda la información de IndexedDB y localStorage a tu nuevo backend.</p>
        </div>
        <div id="omp-body">
          <div id="omp-form">
            <div class="row">
              <label>URL del API (Backend)</label>
              <input id="omp-url" placeholder="https://api.onnestore.rd" type="url"/>
            </div>
            <div class="row">
              <label>Token de autenticación</label>
              <input id="omp-token" placeholder="Bearer token del admin" type="password"/>
            </div>
            <label class="omp-check-row">
              <input id="omp-dry-run" type="checkbox" checked/>
              Modo simulación (dry run) — no envía datos al servidor
            </label>
          </div>

          <div id="omp-preview" style="background:#f9f7f3;border-radius:12px;padding:14px;font-size:.82rem;color:#555;margin-bottom:16px">
            Cargando resumen de datos…
          </div>

          <div id="omp-progress">
            <div id="omp-progress-bar"><div id="omp-progress-fill"></div></div>
            <div id="omp-progress-msg">Iniciando…</div>
          </div>

          <div id="omp-result">
            <div class="omp-stat-grid" id="omp-stats"></div>
            <div id="omp-log"></div>
          </div>

          <div id="omp-actions">
            <button class="omp-btn omp-btn-primary" id="omp-run">▶ Iniciar migración</button>
            <button class="omp-btn omp-btn-secondary" id="omp-export-log" style="display:none">📥 Exportar log</button>
          </div>
        </div>
      </div>`;

      document.body.appendChild(panel);

      // Preview local data
      this._renderPreview();

      // Events
      document.getElementById('omp-close').onclick = () => panel.remove();
      panel.onclick = e => { if(e.target===panel) panel.remove(); };

      document.getElementById('omp-run').onclick = () => this._runMigration();
      document.getElementById('omp-export-log').onclick = () => this._exportLog();
    }

    _renderPreview() {
      const prev = document.getElementById('omp-preview');
      if (!prev) return;
      try {
        const cfg = this.readLocalStorageConfig();
        const prods     = cfg?.products?.length || 0;
        const customers = cfg?.customers?.length || 0;
        const spaces    = cfg?.spaces?.length || 0;
        const botReplies= cfg?.whatsapp?.chatbot?.botReplies?.length || 0;
        prev.innerHTML = `
          <div style="font-weight:700;color:#1e1e1e;margin-bottom:10px">📦 Datos encontrados localmente:</div>
          <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(120px,1fr));gap:8px">
            ${[
              ['Configuración', '1 archivo'],
              ['Productos', prods + ' items'],
              ['Clientes', customers + ' records'],
              ['Espacios', spaces + ' páginas'],
              ['Bot Replies', botReplies + ' reglas'],
            ].map(([k,v]) => `<div style="background:white;border:1px solid #eee;border-radius:8px;padding:10px;font-size:.78rem">
              <div style="font-weight:700;color:#1e1e1e">${v}</div>
              <div style="color:#888">${k}</div>
            </div>`).join('')}
          </div>`;
      } catch(e) {
        prev.textContent = 'Error leyendo datos locales.';
      }
    }

    async _runMigration() {
      const urlEl   = document.getElementById('omp-url');
      const tokenEl = document.getElementById('omp-token');
      const dryEl   = document.getElementById('omp-dry-run');
      const runBtn  = document.getElementById('omp-run');
      const progDiv = document.getElementById('omp-progress');
      const resDv   = document.getElementById('omp-result');

      this.apiUrl  = urlEl?.value.trim() || '';
      this.token   = tokenEl?.value.trim() || '';
      this.dryRun  = dryEl?.checked !== false;

      if (!this.dryRun && !this.apiUrl) {
        alert('Ingresa la URL del API para migración en modo real.');
        return;
      }

      this.api = this.apiUrl ? new ApiClient(this.apiUrl, this.token) : null;
      runBtn.disabled = true;
      progDiv.style.display = 'block';
      resDv.style.display   = 'none';

      this.onProgress = ({ step, current, total, pct, msg }) => {
        const fill = document.getElementById('omp-progress-fill');
        const msgEl = document.getElementById('omp-progress-msg');
        if (fill) fill.style.width = pct + '%';
        if (msgEl) msgEl.textContent = `[${step}] ${msg}`;
      };

      const { summary, logs } = await this.migrateAll();

      // Show results
      resDv.style.display = 'block';
      progDiv.style.display = 'none';

      const stats = document.getElementById('omp-stats');
      if (stats) {
        const r = summary.bySection;
        stats.innerHTML = `
          <div class="omp-stat ${r.config.failed?'err':'ok'}">
            <div class="omp-stat-val">${r.config.done}</div>
            <div class="omp-stat-lbl">Config</div>
          </div>
          <div class="omp-stat ${r.products.failed?'err':'ok'}">
            <div class="omp-stat-val">${r.products.done}</div>
            <div class="omp-stat-lbl">Productos</div>
          </div>
          <div class="omp-stat ${r.customers.failed?'err':'ok'}">
            <div class="omp-stat-val">${r.customers.done}</div>
            <div class="omp-stat-lbl">Clientes</div>
          </div>
          <div class="omp-stat ${r.spaces.failed?'err':'ok'}">
            <div class="omp-stat-val">${r.spaces.done}</div>
            <div class="omp-stat-lbl">Espacios</div>
          </div>
          <div class="omp-stat ok">
            <div class="omp-stat-val">${r.botReplies.done}</div>
            <div class="omp-stat-lbl">Bot Replies</div>
          </div>
          <div class="omp-stat ok">
            <div class="omp-stat-val">${summary.elapsed}</div>
            <div class="omp-stat-lbl">Tiempo</div>
          </div>`;
      }

      const logEl = document.getElementById('omp-log');
      if (logEl) {
        logEl.textContent = logs.map(l => `${l.ts} [${l.level.toUpperCase()}] ${l.msg}${l.data?' — '+JSON.stringify(l.data):''}`).join('\n');
        logEl.scrollTop = logEl.scrollHeight;
      }

      const expBtn = document.getElementById('omp-export-log');
      if (expBtn) expBtn.style.display = 'inline-flex';
      runBtn.disabled = false;
      runBtn.textContent = '↺ Ejecutar de nuevo';
      this._lastResult = { summary, logs };
    }

    _exportLog() {
      if (!this._lastResult) return;
      const blob = new Blob([JSON.stringify(this._lastResult, null, 2)], { type: 'application/json' });
      const a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = `onne-migration-log-${new Date().toISOString().slice(0,10)}.json`;
      a.click();
    }
  }

  // ── Export ──────────────────────────────────────────────────────
  root.OnneMigrator = OnneMigrator;

  // Auto-add migration trigger in admin panel
  if (typeof document !== 'undefined') {
    document.addEventListener('DOMContentLoaded', function() {
      // Add migration button to Setup view if it exists
      const setupView = document.getElementById('view-setup');
      if (!setupView) return;
      
      // Wait for admin to render
      setTimeout(() => {
        const existingBtn = document.getElementById('migration-trigger-btn');
        if (existingBtn) return;

        const card = document.createElement('div');
        card.className = 'admin-card';
        card.style.marginTop = '16px';
        card.innerHTML = `
          <div class="admin-card-title">🚀 Migración a Backend</div>
          <p style="font-size:.82rem;color:#888;margin:0 0 14px">
            Cuando conectes tu backend, usa este sistema para migrar todos los datos 
            (productos, clientes, configuraciones, espacios) de IndexedDB al servidor.
          </p>
          <button class="btn btn-gold btn-sm" id="migration-trigger-btn">
            🚀 Abrir panel de migración
          </button>`;
        
        setupView.appendChild(card);
        
        document.getElementById('migration-trigger-btn').onclick = function() {
          const m = new OnneMigrator({ dryRun: true });
          m.openPanel();
        };
      }, 500);
    });
  }

})(typeof window !== 'undefined' ? window : global);

