      cfg.whatsapp.floatEnabled=!!document.getElementById("wa-float-enabled")?.checked;
      cfg.whatsapp.chatbot=cfg.whatsapp.chatbot||{};
      const cb=cfg.whatsapp.chatbot;
      cb.chatMode=document.getElementById("wa-chat-mode")?.value||"bot";
      cb.name=document.getElementById("wa-chat-name")?.value||"Onne Store";
      cb.subtitle=document.getElementById("wa-chat-subtitle")?.value||"";
      cb.welcome=document.getElementById("wa-chat-welcome")?.value||"";
      cb.defaultReply=document.getElementById("wa-default-reply")?.value||"";
      cb.aiApiKey=document.getElementById("wa-ai-api-key")?.value.trim()||"";
      cb.aiApiKeyFree=document.getElementById("wa-ai-api-key-free")?.value.trim()||"";
      cb.aiFreeModel=document.getElementById("wa-ai-free-model")?.value||"mistralai/mistral-7b-instruct:free";
      cb.knowledgeBase=document.getElementById("wa-knowledge-base")?.value.trim()||"";
      cb.botIcon=document.getElementById("wa-bot-icon")?.value.trim()||"";
      // Save chat color and widget settings
      cfg.whatsapp.style = cfg.whatsapp.style||{};
      const ws = cfg.whatsapp.style;
      const gc=(id)=>document.getElementById(id)?.value||"";
      ws.botBubbleBg      = gc("wa-chat-bot-bubble-bg")   || "#ffffff";
      ws.botBubbleColor   = gc("wa-chat-bot-bubble-color") || "#1e1e1e";
      ws.chatBg           = gc("wa-chat-bg")               || "#f8f9fa";
      ws.quickReplyBg     = gc("wa-chat-quick-reply-bg")   || "#1e7e34";
      ws.sendBtnColor     = gc("wa-chat-send-btn")         || ws.btnColor || "#25D366";
      ws.btnColor         = gc("wa-btn-color")             || "#25D366";
