    // ── Chatbot v71 — Stats & JSON Export ──────────────────────
    function initChatbotStats(){
      const dp=window.ONNE_INTENT_PATTERNS||[];
      const ds=window.ONNE_TRAINING_DATASET||[];
      const am=window.ONNE_AROMA_MAP||{};
      const ur=window.ONNE_UPSELL_RULES||[];
      const cf=window.ONNE_CONVERSATION_FLOWS||{};
      const totalPatterns=dp.reduce((s,ip)=>s+ip.patterns.length,0);

      const statsLine=document.getElementById("cb-stats-line");
      if(statsLine) statsLine.textContent=`Sistema activo · ${dp.length} intenciones · ${totalPatterns} patrones · ${ds.length} preguntas · ${Object.keys(am).length} familias aromáticas`;

      const grid=document.getElementById("cb-stats-grid");
      if(grid){
        const cards=[
          {n:dp.length,       l:"🎯 Intenciones",    c:"#818cf8"},
          {n:totalPatterns,   l:"💬 Patrones",       c:"#34d399"},
          {n:ds.length,       l:"❓ Preguntas",      c:"#60a5fa"},
          {n:Object.keys(am).length, l:"🌸 Familias aroma",c:"#f472b6"},
          {n:ur.length,       l:"⬆️ Reglas upsell",  c:"#fbbf24"},
          {n:Object.keys(cf).length, l:"🔄 Flujos conv.",  c:"#a78bfa"},
        ];
        grid.innerHTML=cards.map(c=>`<div style="background:rgba(255,255,255,.06);border-radius:8px;padding:8px 10px;text-align:center"><div style="font-size:1.3rem;font-weight:800;color:${c.c}">${c.n}</div><div style="font-size:.68rem;color:#94a3b8;margin-top:2px">${c.l}</div></div>`).join("");
      }

      document.getElementById("cb-export-json")?.addEventListener("click",()=>{
        if(!window.ONNE_EXPORT_JSON) return;
        const data=window.ONNE_EXPORT_JSON();
        const blob=new Blob([JSON.stringify(data,null,2)],{type:"application/json"});
        const a=document.createElement("a");
        a.href=URL.createObjectURL(blob);
        a.download="onne-chatbot-dataset-v71.json";
        a.click();
      });

      document.getElementById("cb-view-json")?.addEventListener("click",()=>{
        if(!window.ONNE_EXPORT_JSON) return;
        const data=window.ONNE_EXPORT_JSON();
        const preview=JSON.stringify(data,null,2).substring(0,8000)+"\n... [ver archivo completo]";
        const el=document.getElementById("cb-json-preview");
        if(el) el.value=preview;
        const modal=document.getElementById("cb-json-modal");
        if(modal) modal.style.display="flex";
      });

      const closeModal=()=>{const m=document.getElementById("cb-json-modal");if(m)m.style.display="none";};
      document.getElementById("cb-json-close")?.addEventListener("click", closeModal);
      document.getElementById("cb-json-close2")?.addEventListener("click", closeModal);
      document.getElementById("cb-json-copy")?.addEventListener("click",()=>{
        const el=document.getElementById("cb-json-preview");
        if(el){navigator.clipboard.writeText(el.value).then(()=>toast("JSON copiado","ok")).catch(()=>{el.select();document.execCommand("copy");toast("JSON copiado","ok");});}
      });
      document.getElementById("cb-json-download")?.addEventListener("click",()=>{
        if(!window.ONNE_EXPORT_JSON) return;
        const data=window.ONNE_EXPORT_JSON();
        const blob=new Blob([JSON.stringify(data,null,2)],{type:"application/json"});
        const a=document.createElement("a");
        a.href=URL.createObjectURL(blob);
        a.download="onne-chatbot-dataset-v71.json";
        a.click();
      });
    }

    // ── Knowledge Base: word/char counter ──
    function updateKbWordCount(){
      const kbEl = document.getElementById("wa-knowledge-base");
      const counter = document.getElementById("wa-kb-wordcount");
      const charEl  = document.getElementById("wa-kb-chars");
      if(!kbEl) return;
      const words = kbEl.value.trim() ? kbEl.value.trim().split(/\s+/).length : 0;
      const chars = kbEl.value.length;
      if(counter){
        const pct = Math.round((words/10000)*100);
        counter.textContent = `${words.toLocaleString()} / 10,000 palabras (${pct}%)`;
        counter.style.color = words > 8500 ? "#ef4444" : words > 7000 ? "#f59e0b" : "#16a34a";
      }
      if(charEl) charEl.textContent = `${chars.toLocaleString()} caracteres`;
    }
    document.getElementById("wa-knowledge-base")?.addEventListener("input", updateKbWordCount);
    updateKbWordCount();

    // ── Knowledge Base: clear button ──
    document.getElementById("wa-kb-clear-btn")?.addEventListener("click", ()=>{
      const kbEl = document.getElementById("wa-knowledge-base");
      if(!kbEl) return;
      if(kbEl.value && !confirm("¿Limpiar toda la base de conocimiento?")) return;
      kbEl.value = "";
      updateKbWordCount();
    });

