  function snap() {
    if (!E) return;
    const s = JSON.stringify(E);
    hist = hist.slice(0, histIdx + 1);
    hist.push(s);
    if (hist.length > 80) hist.shift();
    histIdx = hist.length - 1;
  }
  function undo() {
    if (histIdx > 0) { histIdx--; E = JSON.parse(hist[histIdx]); sel = -1; paint(); props(); }
    updateUndoUI();
  }
  function redo() {
    if (histIdx < hist.length - 1) { histIdx++; E = JSON.parse(hist[histIdx]); sel = -1; paint(); props(); }
    updateUndoUI();
  }
  function updateUndoUI() {
    const u = shell?.querySelector('[data-a="undo"]');
    const r = shell?.querySelector('[data-a="redo"]');
    if (u) u.disabled = histIdx <= 0;
    if (r) r.disabled = histIdx >= hist.length - 1;
  }

